INSERT INTO `blog` VALUES
(1,'Ein Wochenende in den Bergen\r\n(1. - 3. Juli 2016)','2016-03-03','Begib dich auf eine Wanderung mit atemberaubender Kulisse vom Tannheimer Tal bis zum Talkessel Reutte.\r\nWir lassen es uns von Hütte zu Hütte mit Übernachtung und Halbpension so richtig gut gehen.\r\nAlso, los geht\'s! Lass dir das nicht entgehen!','Huettenwochenende.jpg',NULL,'2016-07-17 17:09:09'),
(3,'Aktiv-Wochenende in Südtirol\r\n(28. - 30. Oktober 2016)','2016-06-11','Raus aus Alltag, Stress und Arbeit!\r\nRucksack gepackt und auf geht\'s in ein spannendes Wochenende. Erlebe Südtirol in all seiner Vielfalt von seinen schönsten Seiten:\r\nabwechslungsreiche und anspruchsvolle Ganztagswanderung, Erholung und Unterbringung direkt am See, kulinarischer Genuss bei einer Weinverkostung und historische Waalwanderung.','Kalterersee.jpg',NULL,'2016-06-26 14:53:41'),
(10,'Hüttenwochenende Juli 2016\r\nTirol Ausserfern','2016-07-17','Das war unser Wochenende in den Bergen! Wir waren eine feine, kleine und lustige Gruppe haben von allem was mitbekommen. Einsame Hüttenübernachtung nur für uns - traumhaften Sonnenuntergang - Murmeltiere, Gämsen - Hüttengaudi mit Ziach - Sonne, Regen, Nebel und wieder Sonne - alles was das Herz begehrt! Ich möchte mich rechtherzlich Bedanken bei Gerlinde, Hannes, Rainer und Sebastian ihr seid Spitze! Am Ende unserer Tour waren es nämlich ca 40km und ca 2500hm.\r\n\r\n<a href=\"https://goo.gl/photos/gd3LPVipA2SsAYWt8\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> FOTOALBUM</a>','P1100345.jpg',NULL,'2018-09-05 19:10:29'),
(11,'Sunrise August 17','2017-08-24','Schon ein Blick auf den Sonnenaufgang zeigt uns die Schönheit eines Augenblicks.\r\n\r\n<a href=\"https://photos.app.goo.gl/kfQcfHD7NAztc5z72\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> Fotos</a>','DSCN9069.jpg',NULL,'2018-09-05 19:10:38'),
(13,'Aktiv Wanderwochenende in Südtirol Oktober 2016','2016-11-03','...am Freitag fuhren wir über den Brenner zu unser Unterkunft. Nach einem \"Afogato\" gings auf zur Klamm-Wanderung! Samstags, nach einem leckeren Frühstück, rief uns der Berg. Abends ließen wir es uns bei einer Weinverkostung mit Brotzeit gutgehen. Sonntags fuhren wir ins Vinschgau und erwanderten noch einen Waalweg! Es war ein lustiges und traumhaftes Wochenende.... \r\n\r\nDie Vorbereitungen für 2017 laufen! \"Südtirol 2.0\"\r\n\r\nWunschtermine für Mai/ Juni bitte schnellst möglich per Mail an mich senden! \r\n\r\n<a href=\"https://goo.gl/photos/tTgQJYyNXJQ4AnVR6\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> IMPRESSIONEN</a>','DSCN5701.jpg',NULL,'2018-09-05 19:10:49'),
(17,'Gipfelerlebnis der besonderen Art\r\nBike & Hike','2017-05-04','Kürzen Sie mit dem Bike einen langen Aufstieg ab und schonen Sie ihre Gelenke beim Rückweg!\r\nMit der Verbindung zweier wunderbarer Sportarten lässt sich eine Gipfel- oder Hüttentour auf eine besondere Weise erleben. In unserer wunderschönen Natur ein echtes Highlight!\r\n\r\nNatürlich auch mit E-Bike möglich.','bike_Krabachtal.jpg',NULL,'2017-09-06 18:24:13'),
(15,'Iglu bauen \r\nnach alter Tradition','2017-01-21','Lassen Sie sich in die Geheimnisse des Iglubaus einweihen und lernen Sie die Technik der Eskimos','DSC_0018_7.jpg',NULL,'2018-09-05 19:11:00'),
(16,'Erlebnis Winterwandern \r\nTirol /Außerfern','2017-02-13','Eintauchen in die weiße Wunderwelt beim Winterwandern, auf idyllischen Wanderwegen.\r\nDorthin, wo das tief verschneite Außerfern am unberührtesten ist, gelangt man am besten bei einer Schneeschuhwanderung. Sie erlaubt schöne Einblicke in die traumhafte Winterwelt – und bringt dabei den ganzen Körper in Schwung.\r\n\r\n<a href=\"https://goo.gl/photos/EcPwhoq4KWN8A5Wi8\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> FOTOALBUM</a>','DSC_0703.jpg',NULL,'2018-09-05 19:11:11'),
(18,'Hüttenwochenende in den Lechtaler Alpen\r\n(30.Juni - 02.Juli 2017)','2017-05-06','Lass die Zeit stillstehen und gönne dir ein Wochenende in den Bergen. Erhole dich weit weg vom alltäglichen Stress, lebe im Hier und Jetzt mit der Natur.\r\nUrige Hütten (inkl. Übernachtung und Hp), wunderschöne Ausblicke, Naturerlebnis der Extraklasse und ein grandioses Gipfelerlebnis warten auf dich!\r\nUm nur 240€/Person!','DSC_0856.jpg',NULL,'2018-09-05 19:11:23'),
(19,'Geführte E-Bike Touren und auch bike & hike !!\r\nMountainbike, Fahrrad und E-Bike Verleih im Hotel Tannenhof','2017-05-20','Geführte E-Bike Touren in Zusammenarbeit mit dem Tannenhof!\r\nNatürlich auch Bike and Hike möglich!\r\nDer Tannenhof gehört zu den 130 qualitätsgeprüften Rad- und MTB Unterkünften in Tirol und liegt direkt an der VIA CLAUDIA AUGUSTA.\r\n\r\n<a href=\"http://www.tannenhof.cc/rad-mountainbike/\" target=\"_blank\"><i class=\"fa fa-globe\" aria-hidden=\"true\"></i> RAD & MOUNTAINBIKE</a>','Ebike_Touren.jpg',NULL,'2017-09-19 16:20:16'),
(20,'Von Hütte zu Hütte Juli 2017','2017-07-14','Die Natur muss gefühlt werden. (Alexander von Humboldt)\r\nLeider schon wieder vorbei!\r\nEs war wieder eine Hüttentour der Extraklasse! Auf einsamen Wegen von Steinbock, Gams und Murmeltier begleitet wanderten wir abseits des Massentourismus. Das Wetter spielte alle Facetten: Sonne, Regen und auch Hagel war dabei. Die Stimmung war blendend, uns konnte nichts erschüttern.\r\nIch möchte mich recht herzlich bei Michaela, Annett, Mc Raimer, Bene, Sebastian und natürlich auch bei Dagi bedanken. Ihr seid spitze, es war wieder ein wunderschönes Erlebnis mit euch! \r\n\r\n<a href=\"https://goo.gl/photos/YNNjR45Utzbakj4X7\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> Fotos</a>','DSCN7421.jpg',NULL,'2018-09-05 19:11:34'),
(21,'MTB-Club Pfullingen 1996 e.V.','2017-07-26','\"Bike now, work later!\" Der Mtb-Club Pfullingen war ein Wochenende in der Naturparkregion Reutte zu Besuch. Wunderschöne Waldwege und Trails zauberten ein zufriedenes Lächeln ins Gesicht. Die Tiroler Gemütlichkeit kam nicht zu kurz, ebenso die Höhenmeter.\r\n\r\n\r\n<a href=\"https://photos.app.goo.gl/1kPwSktoXFZZk1bD2\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> Album</a>','DSC_0016.jpg',NULL,'2018-09-05 19:11:44'),
(22,'Sonnenaufgang August 16','2016-09-06','Sei geduldig, wenn du im Dunkeln sitzt. Der Sonnenaufgang kommt.\r\n\"Mevlana Dschelaluddin Rumi\"\r\n\r\n\r\n<a href=\"https://goo.gl/photos/1MUx9mKBCDxoBhuT7\" target=\"_blank\"><i class=\"fa fa-camera\" aria-hidden=\"true\"></i> Impressionen</a>','DSCN4625.jpg',NULL,'2018-09-05 19:11:56'),
